public class ELContextManager {
    // Fields
    private Map<String, Method> functions;
    private ThreadLocal<ELEvaluator> current;
    private Context context;
    private ExpressionEvaluator evaluator;
    private Map<String, Object> vars;

    // Constructor
    public ELContextManager(Context context, ExpressionEvaluator evaluator) {
        this.context = context;
        this.evaluator = evaluator;
        this.functions = new java.util.HashMap<>();
        this.current = new ThreadLocal<>();
        this.vars = new java.util.HashMap<>();
    }

    // Convenience method that sets variables in the EL evaluator context
    public void setVariables(Map<String, Object> vars) {
        if (vars == null) {
            return;
        }
        // Update internal store
        this.vars.clear();
        this.vars.putAll(vars);

        // Try to propagate into the current ELEvaluator's context if possible
        ELEvaluator el = current.get();
        if (el != null) {
            try {
                Object elCtx = el.getContext();
                // If the context exposes a setVariables(Map) method, use it
                java.lang.reflect.Method m = elCtx.getClass().getMethod("setVariables", Map.class);
                if (m != null) {
                    m.invoke(elCtx, vars);
                } else {
                    // Fallback: if the context is a Map-like structure
                    if (elCtx instanceof java.util.Map) {
                        @SuppressWarnings("unchecked")
                        java.util.Map<String, Object> ctxMap = (java.util.Map<String, Object>) elCtx;
                        ctxMap.putAll(vars);
                    }
                }
            } catch (Exception ignore) {
                // If propagation fails, silently ignore to preserve existing behavior
            }
        }
    }

    // Other API elements (stubs / minimal implementations)

    public Method resolveFunction(String name) {
        return functions.get(name);
    }

    public void addFunction(String name, Method method) {
        if (name != null && method != null) {
            functions.put(name, method);
        }
    }

    public Object resolveVariable(String name) {
        return vars.get(name);
    }

    public ELEvaluator getCurrent() {
        return current.get();
    }

    public Object getVariable(String name) {
        return vars.get(name);
    }

    public Context getContext() {
        return context;
    }

    public <T> T evaluate(String expression) {
        // Simple delegation to the evaluator, if available
        if (evaluator != null) {
            @SuppressWarnings("unchecked")
            T result = (T) evaluator.evaluate(expression, context);
            return result;
        }
        return null;
    }
}
